// SumWithLabel sums the absolute values of non-zero integers and optionally
// builds a comma-separated detail string. Positive values appear as "n,";
// negative values as "(n),". If label is non-empty, detail is prefixed with "label: ".
// Returns an error when the computed sum is zero.
func SumWithLabel(numbers []int, label string, includeDetail bool) (sum int, detail string, err error) {
	for _, n := range numbers {
		if n > 0 {
			sum += n
			if includeDetail {
				detail += fmt.Sprintf("%d,", n)
			}
		} else if n < 0 {
			sum += -n
			if includeDetail {
				detail += fmt.Sprintf("(%d),", n)
			}
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	if label != "" {
		detail = label + ": " + detail
	}
	return sum, detail, nil
}

// SumAbsAndDetail returns the sum of absolute values of non-zero elements,
// and optionally a human-readable detail string (label-prefixed if label is non-empty).
// If verbose is true, the detail string lists positives as "n," and negatives as "(n),".
// Returns an error when the sum is zero (no non-zero elements).
func SumAbsAndDetail(nums []int, label string, verbose bool) (sum int, detail string, err error) {
	sum = 0
	detail = ""
	for i := 0; i < len(nums); i++ {
		if nums[i] > 0 {
			sum += nums[i]
			if verbose {
				detail += fmt.Sprintf("%d,", nums[i])
			}
		} else if nums[i] < 0 {
			sum += -nums[i]
			if verbose {
				detail += fmt.Sprintf("(%d),", nums[i])
			}
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	if label != "" {
		detail = label + ": " + detail
	}
	return sum, detail, nil
}

func sumAndFormat(nums []int, label string, includeDetail bool) (int, string, error) {
	var sum int
	var sb strings.Builder
	for _, n := range nums {
		if n > 0 {
			sum += n
			if includeDetail {
				sb.WriteString(fmt.Sprintf("%d,", n))
			}
		} else if n < 0 {
			sum += -n
			if includeDetail {
				sb.WriteString(fmt.Sprintf("(%d),", n))
			}
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	s := sb.String()
	if label != "" {
		s = label + ": " + s
	}
	return sum, s, nil
}

func sumAbsoluteAndFormat(values []int, label string, includeDetail bool) (int, string, error) {
	var sum int
	var parts []string
	for _, v := range values {
		if v > 0 {
			sum += v
			if includeDetail {
				parts = append(parts, fmt.Sprintf("%d", v))
			}
		} else if v < 0 {
			sum -= v
			if includeDetail {
				parts = append(parts, fmt.Sprintf("(%d)", v))
			}
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	var s string
	if includeDetail {
		s = strings.Join(parts, ",") + ","
		if label != "" {
			s = label + ": " + s
		}
	}
	return sum, s, nil
}

func SumWithOptionalFormat(nums []int, prefix string, includeFormat bool) (int, string, error) {
	var sum int
	var b strings.Builder
	for _, n := range nums {
		if n > 0 {
			sum += n
			if includeFormat {
				b.WriteString(fmt.Sprintf("%d,", n))
			}
		} else if n < 0 {
			sum += -n
			if includeFormat {
				b.WriteString(fmt.Sprintf("(%d),", n))
			}
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", prefix)
	}
	s := b.String()
	if prefix != "" {
		s = prefix + ": " + s
	}
	return sum, s, nil
}
